/** Get city with localized names based on language */
export function getLocalizedCity(city: CityConfig, lang: "uk" | "ru") {
  if (lang === "uk") return city;
  const ru = CITIES_RU[city.slug];
  if (!ru) return city;
  return {
    ...city,
    name: ru.name,
    nameGenitive: ru.nameGenitive,
    seoTitle: ru.seoTitle,
    seoDescription: ru.seoDescription,
  };
}

export function getRuCitySlug(cityOrSlug: CityConfig | string) {
  const sourceSlug = typeof cityOrSlug === "string" ? cityOrSlug : cityOrSlug.slug;
  return CITIES_RU[sourceSlug]?.slug ?? sourceSlug;
}

export function getCityByRuSlug(slug: string, cities: CityConfig[]) {
  return cities.find((city) => getRuCitySlug(city) === slug);
}
